// n8n's HTTP Request node may return the array as a single item (json=array)
// or split it into one item per element (each json=supplier). Handle both.
const items = $input.all();
const list = items.flatMap((i) => {
  const j = i.json;
  if (Array.isArray(j)) return j;
  // Sometimes the response is wrapped: { data: [...] } or { body: [...] }
  if (j && Array.isArray(j.data)) return j.data;
  if (j && Array.isArray(j.body)) return j.body;
  return j && typeof j === 'object' ? [j] : [];
});
const vg = list.find((s) => s && s.slug === 'vg-ops');
if (!vg) {
  throw new Error(`VG OPS supplier not found. Saw ${list.length} suppliers: ${list.map(s => s?.slug).join(',')}`);
}
if (!vg.is_active) {
  throw new Error("VG OPS supplier is_active=false. Flip it: UPDATE suppliers SET is_active=true WHERE slug='vg-ops';");
}
return [{ json: { vg_sid: vg.id, vg_name: vg.name } }];

// Categories disabled — empty catMap so category_name falls through to default_category_name.
const catMap = new Map();

// Flatten any OPS response shape:
//  A) { data: { products_details: { products: [...] } } }
//  B) flat array of products
//  C) single product object per item
const flatProducts = $input.all().flatMap((item) => {
  const j = item.json ?? {};
  const nested = j?.data?.products_details?.products;
  if (Array.isArray(nested)) return nested;
  if (Array.isArray(j)) return j;
  if (j && typeof j === 'object' && (j.products_id || j.product_id || j.id)) return [j];
  return [];
});

const stripHtml = (s) => (typeof s === 'string'
  ? s.replace(/<style[\s\S]*?<\/style>/gi, '')
     .replace(/<script[\s\S]*?<\/script>/gi, '')
     .replace(/<[^>]+>/g, '')
     .replace(/&nbsp;/g, ' ')
     .replace(/\s+/g, ' ')
     .trim() || null
  : null);

// "Decals - General Performance (Arlon - 510MT)" -> "Arlon"
const brandFromInternalName = (s) => {
  if (typeof s !== 'string') return null;
  const m = s.match(/\(([^)]+)\)\s*$/);
  if (!m) return null;
  return (m[1].split(/\s*-\s*/)[0] || '').trim() || null;
};

// "Through Cut_Knife|2" -> "Through Cut", "None_lamMaterial" -> "None", "Rectangle|1" -> "Rectangle"
const titleFromAttributeKey = (k) => {
  if (typeof k !== 'string' || !k) return 'Untitled';
  const beforePipe = k.split('|')[0];
  const beforeUnderscore = beforePipe.split('_')[0];
  return beforeUnderscore.trim() || beforePipe.trim() || 'Untitled';
};

const toNum = (v) => (v == null || v === '' ? null : Number(v));

return flatProducts.map((p) => {
  const productId = p.products_id ?? p.product_id ?? p.id;
  const productIdStr = productId != null ? String(productId) : '';
  const catExt = p.default_category_id != null ? String(p.default_category_id) : null;

  const variants = (p.product_size ?? []).map((s) => {
    const sizeId = s.product_size_id ?? s.size_id;
    const sizeIdStr = sizeId != null ? String(sizeId) : '';
    return {
      part_id: sizeIdStr,
      color: s.product_default_color ?? s.color ?? null,
      size: s.product_size_label ?? s.size_label ?? s.size_title ?? null,
      sku: s.product_size_sku ?? (sizeIdStr ? `${productIdStr}-${sizeIdStr}` : null),
      base_price: null,
      inventory: null,
      warehouse: null,
    };
  });

  const images = [];
  if (p.small_image) images.push({ url: p.small_image, image_type: 'front', color: null, sort_order: 0 });
  if (p.large_image && p.large_image !== p.small_image) {
    images.push({ url: p.large_image, image_type: 'back', color: null, sort_order: 1 });
  }

  const options = (p.product_additional_options ?? [])
    .map((o, i) => {
      const key = o.option_key ?? o.optionKey ?? '';
      const rawTitle = o.title ?? o.option_title ?? o.optionTitle ?? '';
      const title = (typeof rawTitle === 'string' && rawTitle.trim()) || key || 'Option';
      const firstProdAddOptId = Array.isArray(o.attributes) && o.attributes[0]?.prod_add_opt_id;
      const opsOptionId = o.product_additional_option_id ?? (firstProdAddOptId != null ? firstProdAddOptId : null);
      const reqRaw = o.required;
      const required = !(reqRaw == null || reqRaw === '' || reqRaw === '0' || reqRaw === 0 || reqRaw === false);

      // Remap each OPS attribute to backend OptionAttributeIngest shape.
      // Backend requires `title: str` — derive from attribute_key.
      const rawAttrs = Array.isArray(o.attributes) ? o.attributes : [];
      const attributes = rawAttrs.map((a) => ({
        title: titleFromAttributeKey(a.attribute_key),
        sort_order: Number(a.sort_order ?? 0),
        ops_attribute_id: a.attribute_id != null ? Number(a.attribute_id) : null,
        master_attribute_id: a.master_attribute_id != null ? Number(a.master_attribute_id) : null,
        attribute_key: typeof a.attribute_key === 'string' ? a.attribute_key : null,
        price: null,
        setup_cost: toNum(a.setup_cost),
        multiplier: toNum(a.multiplier),
      }));

      return {
        option_key: String(key),
        title: String(title),
        options_type: o.options_type ?? o.optionsType ?? null,
        sort_order: Number(o.sort_order ?? o.sortOrder ?? i),
        master_option_id: o.master_option_id != null ? Number(o.master_option_id) : null,
        ops_option_id: null,
        required,
        attributes,
      };
    })
    .filter((o) => o.option_key);

  return {
    json: {
      supplier_sku: p.products_sku ?? p.main_sku ?? productIdStr,
      product_name: p.products_title ?? p.product_name ?? 'Untitled',
      brand: p.brand_name ?? brandFromInternalName(p.products_internal_name),
      description:
        stripHtml(p.short_description) ||
        stripHtml(p.long_description) ||
        stripHtml(p.long_description_two) ||
        null,
      product_type: p.predefined_product_type === '1' || p.predefined_product_type === 1 ? 'apparel' : 'standard',
      image_url: p.small_image ?? p.large_image ?? null,
      ops_product_id: productIdStr,
      external_catalogue: 1,
      category_external_id: catExt,
      category_name: catExt ? (catMap.get(catExt) ?? p.default_category_name ?? null) : null,
      variants,
      images,
      options,
    },
  };
});
